class SecureModelLoader:
    def __init__(self, model_path: Optional[str] = None, 
                 trusted_hashes_path: Optional[str] = None,
                 allowed_extensions: Optional[list] = None):
        self.model_path = model_path or os.getenv('MODEL_PATH')
        self.trusted_hashes_path = trusted_hashes_path or os.getenv('TRUSTED_HASHES_PATH', 'trusted_hashes.json')
        self.allowed_extensions = allowed_extensions or ['.pkl', '.joblib', '.h5', '.pt', '.pth', '.onnx']
        self.trusted_hashes = self._load_trusted_hashes()
        self.loaded_model = None
        self.model_metadata = {}
        
    def _load_trusted_hashes(self) -> Dict[str, str]:
        if os.path.exists(self.trusted_hashes_path):
            with open(self.trusted_hashes_path, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_trusted_hashes(self):
        with open(self.trusted_hashes_path, 'w') as f:
            json.dump(self.trusted_hashes, f, indent=2)
    
    def _calculate_hash(self, file_path: str, algorithm: str = 'sha256') -> str:
        hash_func = hashlib.new(algorithm)
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(4096), b''):
                hash_func.update(chunk)
        return hash_func.hexdigest()
    
    def _verify_file_extension(self, file_path: str) -> bool:
        ext = Path(file_path).suffix.lower()
        return ext in self.allowed_extensions
    
    def _verify_hash(self, file_path: str, expected_hash: Optional[str] = None) -> bool:
        if not expected_hash:
            model_name = Path(file_path).name
            expected_hash = self.trusted_hashes.get(model_name)
            if not expected_hash:
                return False
        
        actual_hash = self._calculate_hash(file_path)
        return actual_hash == expected_hash
    
    def register_trusted_model(self, file_path: str, model_name: Optional[str] = None):
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"Model file not found: {file_path}")
        
        if not self._verify_file_extension(file_path):
            raise ValueError(f"File extension not allowed: {file_path}")
        
        model_name = model_name or Path(file_path).name
        model_hash = self._calculate_hash(file_path)
        
        self.trusted_hashes[model_name] = model_hash
        self._save_trusted_hashes()
        
        print(f"Registered trusted model: {model_name} with hash: {model_hash}")
    
    def _safe_pickle_load(self, file_path: str):
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                safe_modules = {
                    'numpy', 'numpy.core', 'numpy.core.multiarray',
                    'sklearn', 'sklearn.tree', 'sklearn.ensemble', 'sklearn.linear_model',
                    'sklearn.svm', 'sklearn.neighbors', 'sklearn.naive_bayes',
                    'pandas', 'pandas.core', 'pandas.core.frame', 'pandas.core.series',
                    'scipy', 'scipy.sparse',
                    'builtins', '__builtin__'
                }
                
                safe_classes = {
                    'dict', 'list', 'tuple', 'set', 'frozenset',
                    'int', 'float', 'str', 'bool', 'bytes',
                    'ndarray', 'dtype', 'Series', 'DataFrame'
                }
                
                module_base = module.split('.')[0]
                if module_base not in safe_modules and module not in safe_modules:
                    raise pickle.UnpicklingError(f"Unsafe module: {module}")
                
                if name.startswith('_') and name not in safe_classes:
                    raise pickle.UnpicklingError(f"Unsafe class: {name}")
                
                return super().find_class(module, name)
        
        with open(file_path, 'rb') as f:
            return RestrictedUnpickler(f).load()
    
    def _load_model_file(self, file_path: str):
        ext = Path(file_path).suffix.lower()
        
        if ext == '.pkl':
            return self._safe_pickle_load(file_path)
        elif ext == '.joblib':
            return joblib.load(file_path)
        elif ext in ['.h5']:
            try:
                import tensorflow as tf
                return tf.keras.models.load_model(file_path)
            except ImportError:
                raise ImportError("TensorFlow not installed")
        elif ext in ['.pt', '.pth']:
            try:
                import torch
                return torch.load(file_path, map_location='cpu', weights_only=True)
            except ImportError:
                raise ImportError("PyTorch not installed")
        elif ext == '.onnx':
            try:
                import onnxruntime as ort
                return ort.InferenceSession(file_path)
            except ImportError:
                raise ImportError("ONNX Runtime not installed")
        else:
            raise ValueError(f"Unsupported file extension: {ext}")
    
    def load_model(self, model_path: Optional[str] = None, 
                   verify_hash: bool = True,
                   expected_hash: Optional[str] = None) -> Any:
        model_path = model_path or self.model_path
        
        if not model_path:
            raise ValueError("Model path not provided")
        
        if not os.path.exists(model_path):
            raise FileNotFoundError(f"Model file not found: {model_path}")
        
        if not self._verify_file_extension(model_path):
            raise ValueError(f"File extension not allowed: {model_path}")
        
        if verify_hash:
            if not self._verify_hash(model_path, expected_hash):
                raise ValueError(f"Hash verification failed for: {model_path}")
        
        self.loaded_model = self._load_model_file(model_path)
        self.model_metadata = {
            'path': model_path,
            'hash': self._calculate_hash(model_path),
            'name': Path(model_path).name
        }
        
        print(f"Successfully loaded model: {self.model_metadata['name']}")
        return self.loaded_model
    
    def get_model(self) -> Any:
        if self.loaded_model is None:
            raise RuntimeError("No model loaded. Call load_model() first.")
        return self.loaded_model
    
    def get_metadata(self) -> Dict[str, Any]:
        return self.model_metadata


class CloudModelLoader(SecureModelLoader):
    def __init__(self, cloud_provider: str = 'auto', **kwargs):
        super().__init__(**kwargs)
        self.cloud_provider = cloud_provider or os.getenv('CLOUD_PROVIDER', 'auto')
        self.temp_dir = tempfile.mkdtemp(prefix='secure_models_')
        
    def __del__(self):
        if hasattr(self, 'temp_dir') and os.path.exists(self.temp_dir):
            shutil.rmtree(self.temp_dir)
    
    def _download_from_s3(self, s3_path: str, local_path: str):
        import boto3
        s3 = boto3.client('s3')
        
        parts = s3_path.replace('s3://', '').split('/', 1)
        bucket = parts[0]
        key = parts[1] if len(parts) > 1 else ''
        
        s3.download_file(bucket, key, local_path)
    
    def _download_from_gcs(self, gcs_path: str, local_path: str):
        from google.cloud import storage
        client = storage.Client()
        
        parts = gcs_path.replace('gs://', '').split('/', 1)
        bucket_name = parts[0]
        blob_name = parts[1] if len(parts) > 1 else ''
        
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        blob.download_to_filename(local_path)
    
    def _download_from_azure(self, azure_path: str, local_path: str):
        from azure.storage.blob import BlobServiceClient
        
        parts = azure_path.replace('https://', '').split('/', 2)
        account_url = f"https://{parts[0]}"
        container = parts[1]
        blob_name = parts[2] if len(parts) > 2 else ''
        
        blob_service_client = BlobServiceClient(account_url=account_url)
        blob_client = blob_service_client.get_blob_client(container=container, blob=blob_name)
        
        with open(local_path, 'wb') as f:
            f.write(blob_client.download_blob().readall())
    
    def download_model(self, cloud_path: str) -> str:
        local_filename = Path(cloud_path).name
        local_path = os.path.join(self.temp_dir, local_filename)
        
        if cloud_path.startswith('s3://'):
            self._download_from_s3(cloud_path, local_path)
        elif cloud_path.startswith('gs://'):
            self._download_from_gcs(cloud_path, local_path)
        elif cloud_path.startswith('https://') and 'blob.core.windows.net' in cloud_path:
            self._download_from_azure(cloud_path, local_path)
        else:
            raise ValueError(f"Unsupported cloud path: {cloud_path}")
        
        return local_path
    
    def load_from_cloud(self, cloud_path: Optional[str] = None,
                       verify_hash: bool = True,
                       expected_hash: Optional[str] = None) -> Any:
        cloud_path = cloud_path or self.model_path
        
        if not cloud_path:
            raise ValueError("Cloud path not provided")
        
        print(f"Downloading model from: {cloud_path}")
        local_path = self.download_model(cloud_path)
        
        return self.load_model(local_path, verify_hash=verify_hash, expected_hash=expected_hash)


